import React, { useState } from 'react';
import API from '../api/axios';
import { useNavigate } from 'react-router-dom';

const Login = () => {
    const [email, setEmail] = useState('');
    const [password, setPassword] = useState('');
    const [loading, setLoading] = useState(false);
    const [errorMessage, setErrorMessage] = useState('');
    const navigate = useNavigate();

    const handleLogin = async (e) => {
        e.preventDefault();
        setLoading(true);
        setErrorMessage('');
        try {
            const { data } = await API.post('/auth/login', { email, password });

            localStorage.setItem('token', data.token);
            localStorage.setItem('role', data.role);
            localStorage.setItem('userName', data.userName || data.email || 'User');
            localStorage.setItem('userId', data.userId);
            setErrorMessage('');
            navigate('/dashboard');
        } catch (err) {
            const message = err.response?.data?.message || "Invalid email or password";
            setErrorMessage(message);
            console.error('Login error:', message);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={styles.loginPage}>
            <style>{`
                @import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

                * {
                    margin: 0;
                    padding: 0;
                    box-sizing: border-box;
                    font-family: 'Inter', sans-serif;
                }

                .background-orb {
                    position: absolute;
                    width: 300px;
                    height: 300px;
                    border-radius: 50%;
                    filter: blur(120px);
                    opacity: 0.6;
                    animation: float 8s infinite ease-in-out;
                }

                .orb1 {
                    background: #ff00cc;
                    top: 10%;
                    left: 15%;
                }

                .orb2 {
                    background: #00c6ff;
                    bottom: 15%;
                    right: 20%;
                    animation-delay: 4s;
                }

                @keyframes float {
                    0%, 100% { transform: translateY(0); }
                    50% { transform: translateY(-40px); }
                }

                .login-container {
                    position: relative;
                    width: 100%;
                    max-width: 420px;
                    padding: 50px 40px;
                    background: rgba(20, 20, 30, 0.85);
                    border-radius: 20px;
                    box-shadow: 0 0 25px rgba(0, 198, 255, 0.4);
                    border: 1px solid rgba(255, 255, 255, 0.1);
                    z-index: 2;
                    animation: fadeIn 0.8s ease;
                }

                @keyframes fadeIn {
                    from { opacity: 0; transform: scale(0.95); }
                    to { opacity: 1; transform: scale(1); }
                }

                .login-header {
                    text-align: center;
                    margin-bottom: 35px;
                }

                .welcome-title {
                    font-size: 28px;
                    font-weight: 700;
                    background: linear-gradient(90deg, #00c6ff, #ff00cc);
                    -webkit-background-clip: text;
                    -webkit-text-fill-color: transparent;
                    margin-bottom: 12px;
                }

                .welcome-subtitle {
                    font-size: 15px;
                    color: rgba(255, 255, 255, 0.7);
                }

                .form-group {
                    margin-bottom: 22px;
                }

                .form-label {
                    display: block;
                    font-size: 14px;
                    font-weight: 500;
                    color: #fff;
                    margin-bottom: 8px;
                }

                .form-input {
                    width: 100%;
                    padding: 14px 18px;
                    font-size: 14px;
                    border: none;
                    border-radius: 12px;
                    background: rgba(255, 255, 255, 0.08);
                    color: #fff;
                    transition: all 0.3s ease;
                }

                .form-input:focus {
                    outline: none;
                    background: rgba(255, 255, 255, 0.15);
                    box-shadow: 0 0 0 2px #00c6ff;
                }

                .form-input::placeholder {
                    color: rgba(255, 255, 255, 0.5);
                }

                .login-button {
                    width: 100%;
                    padding: 15px;
                    background: linear-gradient(135deg, #00c6ff 0%, #ff00cc 100%);
                    color: white;
                    border: none;
                    border-radius: 12px;
                    font-size: 15px;
                    font-weight: 600;
                    cursor: pointer;
                    transition: transform 0.2s ease, box-shadow 0.2s ease;
                    margin-top: 12px;
                }

                .login-button:hover {
                    transform: translateY(-2px);
                    box-shadow: 0 6px 20px rgba(255, 0, 204, 0.4);
                }

                .login-button:disabled {
                    background: #555;
                    cursor: not-allowed;
                }

                .error-message {
                    background: rgba(255, 0, 0, 0.15);
                    color: #ff4d4d;
                    padding: 12px 16px;
                    border-radius: 12px;
                    font-size: 14px;
                    margin-bottom: 20px;
                    border: 1px solid rgba(255, 0, 0, 0.3);
                    text-align: center;
                }

                @media (max-width: 480px) {
                    .login-container {
                        padding: 35px 28px;
                        margin: 0 16px;
                    }
                }
            `}</style>

            <div className="background-orb orb1"></div>
            <div className="background-orb orb2"></div>

            <div className="login-container">
                <div className="login-header">
                    <h1 className="welcome-title">Welcome Back</h1>
                    <p className="welcome-subtitle">Sign in to access your dashboard</p>
                </div>

                {errorMessage && (
                    <div className="error-message">
                        {errorMessage}
                    </div>
                )}

                <form onSubmit={handleLogin}>
                    <div className="form-group">
                        <label className="form-label">Email</label>
                        <input
                            type="email"
                            className="form-input"
                            placeholder="Enter your email"
                            value={email}
                            onChange={e => setEmail(e.target.value)}
                            required
                        />
                    </div>

                    <div className="form-group">
                        <label className="form-label">Password</label>
                        <input
                            type="password"
                            className="form-input"
                            placeholder="Enter your password"
                            value={password}
                            onChange={e => setPassword(e.target.value)}
                            required
                        />
                    </div>

                    <button 
                        type="submit" 
                        className="login-button"
                        disabled={loading}
                    >
                        {loading ? 'Signing in...' : 'Sign in'}
                    </button>
                </form>
            </div>
        </div>
    );
};

const styles = {
    loginPage: {
        minHeight: '100vh',
        display: 'flex',
        justifyContent: 'center',
        alignItems: 'center',
        background: 'radial-gradient(circle at top left, #1a1a2e, #16213e)',
        padding: '20px',
        position: 'relative',
        overflow: 'hidden',
    },
};

export default Login;
